function depositIntoPool(uint256 amount) external {
    if (amount == 0) {
        revert ZeroAmount();
    }

    depositBalance[msg.sender] += amount;
    IERC20(stakeToken).safeTransferFrom(msg.sender, address(this), amount);

    emit StakeDeposited(msg.sender, amount);
}
